// ---------------------------------------------
// YouTrend: Metrics Evaluation Code Node
// Input: raw YouTube videos.list response (1 item, .items = array)
// Output: one n8n item per video with cleaned metrics
// ---------------------------------------------

const response = $input.first().json;
const videos = response.items || [];

const results = [];

for (const video of videos) {
  try {
    const snippet = video.snippet || {};
    const stats = video.statistics || {};

    // Safely parse numeric stats, defaulting missing/hidden counts to 0
    const viewCount = parseInt(stats.viewCount, 10) || 0;
    const likeCount = parseInt(stats.likeCount, 10) || 0;
    const commentCount = parseInt(stats.commentCount, 10) || 0;

    // Avoid divide-by-zero: if viewCount is 0, engagementRate is 0
    const engagementRate = viewCount > 0
      ? ((likeCount + commentCount) / viewCount) * 100
      : 0;

    results.push({
      json: {
        videoId: video.id || '',
        title: (snippet.title || '').trim(),
        description: (snippet.description || '').slice(0, 1000), // cap length for AI prompt
        tags: snippet.tags || [],
        viewCount,
        likeCount,
        commentCount,
        engagementRate: Number(engagementRate.toFixed(4)),
        publishedAt: snippet.publishedAt || null
      }
    });
  } catch (err) {
    // Never let one malformed video break the whole batch
    results.push({
      json: {
        videoId: video.id || 'UNKNOWN',
        error: `Failed to process video: ${err.message}`
      }
    });
  }
}

return results;

// ---------------------------------------------
// Merge OpenAI JSON output back with the metrics item
// and guard against malformed/missing AI JSON
// ---------------------------------------------
const metrics = $('Calculate Engagement Metrics').item.json;
const aiRaw = $json.message?.content ?? $json.content ?? $json.text ?? '{}';

let parsed;
try {
  parsed = typeof aiRaw === 'string' ? JSON.parse(aiRaw) : aiRaw;
} catch (e) {
  parsed = { macro_category: 'Uncategorized', semantic_tags: [] };
}

return [{
  json: {
    videoId: metrics.videoId,
    title: metrics.title,
    viewCount: metrics.viewCount,
    likeCount: metrics.likeCount,
    commentCount: metrics.commentCount,
    engagementRate: metrics.engagementRate,
    publishedAt: metrics.publishedAt,
    macro_category: parsed.macro_category || 'Uncategorized',
    semantic_tags: Array.isArray(parsed.semantic_tags) ? parsed.semantic_tags : []
  }
}];

// Catches items that errored out of the YouTube or OpenAI nodes
// so failures are visible in the execution log instead of silently dropped.
const item = $input.first().json;
console.log('Pipeline error captured:', JSON.stringify(item));
return [{ json: { ...item, pipelineStage: 'error', loggedAt: new Date().toISOString() } }];
